package genxsolution.vms.vmsbackend.maintenance_management.maintenance_plan_item.controller;
import genxsolution.vms.vmsbackend.common.query.ListQueryEngine; import genxsolution.vms.vmsbackend.maintenance_management.maintenance_plan_item.dto.*; import genxsolution.vms.vmsbackend.maintenance_management.maintenance_plan_item.service.MaintenancePlanItemService; import org.springframework.http.HttpStatus; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api/v1/vehicles/maintenance-plan-items") public class MaintenancePlanItemController { private final MaintenancePlanItemService service; public MaintenancePlanItemController(MaintenancePlanItemService service){this.service=service;} @GetMapping public List<MaintenancePlanItemResponse> list(@RequestParam(required=false) UUID companyId,@RequestParam Map<String,String> filters){ return ListQueryEngine.apply(service.list(companyId), filters, Set.of("companyId")); } @GetMapping("/{id}") public MaintenancePlanItemResponse getById(@PathVariable UUID id){ return service.getById(id);} @PostMapping @ResponseStatus(HttpStatus.CREATED) public MaintenancePlanItemResponse create(@RequestBody MaintenancePlanItemUpsertRequest r){ return service.create(r);} @PutMapping("/{id}") public MaintenancePlanItemResponse update(@PathVariable UUID id,@RequestBody MaintenancePlanItemUpsertRequest r){ return service.update(id,r);} @DeleteMapping("/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) public void delete(@PathVariable UUID id){ service.delete(id);} }
